#[derive(Debug, Clone, Default)]
struct CliGlobalOptions {
    admin_token: Option<String>,
}

static CLI_ADMIN_TOKEN: OnceLock<String> = OnceLock::new();

fn render_help() -> &'static str {
    r#"uhostctl v0.1 beta

Usage:
  uhostctl <command> [subcommand] [options]

Top-level commands:
  init [path]    Write a sample all-in-one config file
  sample         Print a sample all-in-one config to stdout
  token          Generate URL-safe admin/bootstrap tokens
  ha             High-availability and failover operations
  dr             Disaster-recovery drill operations
  migrate        Migration manifest and rollout operations
  lifecycle      Lifecycle extension and compatibility operations
  repair         Repair and remediation operations
  identity       Identity and auth operations
  secrets        Secret grant and reveal operations
  ingress        Ingress routing operations
  data           Data-service maintenance operations
  stream         Stream service operations
  policy         Policy and approval operations
  mail           Mail and DNS-auth operations
  abuse          Abuse, remediation, and support-case operations
  governance     Governance and audit operations
  notify         Notification operations
  uvm            UVM control, image, runtime, and evidence operations
  release        Artifact verification and release operations

Global options:
  --admin-token <token>

Use the subcommand-specific usage text for detailed flags.
"#
}

fn main() -> Result<()> {
    let mut args = env::args().skip(1).collect::<Vec<_>>();
    let global_options = extract_global_options(&mut args)?;
    if let Some(token) = global_options.admin_token.as_ref() {
        let _ = CLI_ADMIN_TOKEN.set(token.clone());
    }
    if args.is_empty() {
        print!("{}", render_help());
        return Ok(());
    }

    let command = args.remove(0);
    match command.as_str() {
        "-h" | "--help" | "help" => {
            print!("{}", render_help());
            Ok(())
        }
        "init" => {
            let output = args
                .first()
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from("configs/dev/all-in-one.toml"));
            write_init_config(output)
        }
        "sample" => {
            print!("{}", render_sample_config("generated-node", "./state")?);
            Ok(())
        }
        "token" => cmd_token(&args),
        "ha" => cmd_ha(&args),
        "dr" => cmd_dr(&args),
        "migrate" => cmd_migrate(&args),
        "lifecycle" => cmd_lifecycle(&args),
        "repair" => cmd_repair(&args),
        "identity" => cmd_identity(&args),
        "secrets" => cmd_secrets(&args),
        "ingress" => cmd_ingress(&args),
        "data" => cmd_data(&args),
        "stream" => cmd_stream(&args),
        "policy" => cmd_policy(&args),
        "mail" => cmd_mail(&args),
        "abuse" => cmd_abuse(&args),
        "governance" => cmd_governance(&args),
        "notify" => cmd_notify(&args),
        "uvm" => cmd_uvm(&args),
        "release" => cmd_release(&args),
        other => Err(PlatformError::invalid(format!(
            "unsupported command `{other}`\n\n{}",
            render_help()
        ))),
    }
}

fn write_init_config(path: PathBuf) -> Result<()> {
    let parent = path.parent().unwrap_or_else(|| std::path::Path::new("."));
    fs::create_dir_all(parent).map_err(|error| {
        PlatformError::unavailable("failed to create config directory")
            .with_detail(error.to_string())
    })?;
    let config = render_sample_config("dev-node", "./state")?;
    fs::write(&path, config).map_err(|error| {
        PlatformError::unavailable("failed to write config file").with_detail(error.to_string())
    })?;
    println!("wrote {}", path.display());
    Ok(())
}

fn render_sample_config(node_name: &str, state_dir: &str) -> Result<String> {
    let master_key = base64url_encode(&random_bytes(32)?);
    let bootstrap_admin_token = generate_cli_token(24)?;
    Ok(format!(
        r#"# Generated by `uhostctl init`.
# `bootstrap_admin_token` is a generated URL-safe bearer token.
# Generate a replacement with `uhostctl token generate`.
listen = "127.0.0.1:9080"
state_dir = "{state_dir}"

[schema]
schema_version = 1
mode = "all_in_one"
node_name = "{node_name}"

[secrets]
master_key = "{master_key}"

[security]
bootstrap_admin_token = "{bootstrap_admin_token}"
"#
    ))
}

fn cmd_token(args: &[String]) -> Result<()> {
    match args.first().map(String::as_str) {
        Some("generate") => {
            let byte_len = option_value(args, "--bytes")
                .map(|value| {
                    value.parse::<usize>().map_err(|error| {
                        PlatformError::invalid("invalid --bytes").with_detail(error.to_string())
                    })
                })
                .transpose()?
                .unwrap_or(24);
            let token = generate_cli_token(byte_len)?;
            if has_flag(args, "--shell") {
                let variable = validate_shell_env_name(
                    option_value(args, "--env")
                        .unwrap_or_else(|| String::from("UHOSTCTL_ADMIN_TOKEN"))
                        .as_str(),
                )?;
                println!("{}", render_token_shell_export(&variable, &token));
            } else {
                println!("{token}");
            }
            Ok(())
        }
        _ => Err(PlatformError::invalid(
            "usage: uhostctl token generate [--bytes <n>] [--shell] [--env <NAME>]",
        )),
    }
}

fn generate_cli_token(byte_len: usize) -> Result<String> {
    if !(16..=64).contains(&byte_len) {
        return Err(PlatformError::invalid(
            "token entropy bytes must be between 16 and 64",
        ));
    }
    Ok(base64url_encode(&random_bytes(byte_len)?))
}

fn validate_shell_env_name(value: &str) -> Result<String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Err(PlatformError::invalid("shell env name may not be empty"));
    }
    let mut characters = trimmed.chars();
    let Some(first) = characters.next() else {
        return Err(PlatformError::invalid("shell env name may not be empty"));
    };
    if !(first.is_ascii_alphabetic() || first == '_') {
        return Err(PlatformError::invalid(
            "shell env name must start with an ASCII letter or underscore",
        ));
    }
    if !characters.all(|character| character.is_ascii_alphanumeric() || character == '_') {
        return Err(PlatformError::invalid(
            "shell env name may only contain ASCII letters, digits, and underscores",
        ));
    }
    Ok(trimmed.to_owned())
}

fn render_token_shell_export(variable: &str, token: &str) -> String {
    format!("export {variable}={token}")
}

