fn parse_backend_specs(values: &[String]) -> Result<Vec<serde_json::Value>> {
    let mut backends = Vec::with_capacity(values.len());
    for value in values {
        let trimmed = value.trim();
        if trimmed.is_empty() {
            return Err(PlatformError::invalid("backend target may not be empty"));
        }
        let (target, weight) = if let Some((target, weight)) = trimmed.rsplit_once('@') {
            let parsed_weight = weight.parse::<u16>().map_err(|error| {
                PlatformError::invalid("invalid backend weight").with_detail(error.to_string())
            })?;
            (target.trim(), parsed_weight)
        } else {
            (trimmed, 1_u16)
        };
        if target.is_empty() {
            return Err(PlatformError::invalid("backend target may not be empty"));
        }
        backends.push(serde_json::json!({
            "target": target,
            "weight": weight.max(1),
        }));
    }
    Ok(backends)
}

