fn cmd_uvm_compat(args: &[String]) -> Result<()> {
    match args.first().map(String::as_str) {
        Some("check") => {
            let endpoint = option_value(args, "--endpoint")
                .unwrap_or_else(|| String::from("http://127.0.0.1:9080"));
            let matrix_raw = get_json(&endpoint, "/uvm/compatibility-matrix")?;
            let native_claim_raw = get_json(&endpoint, "/uvm/native-claim-status")?;
            let matrix: serde_json::Value = serde_json::from_str(&matrix_raw).map_err(|error| {
                PlatformError::invalid("invalid JSON from /uvm/compatibility-matrix")
                    .with_detail(error.to_string())
            })?;
            let native_claim: serde_json::Value =
                serde_json::from_str(&native_claim_raw).map_err(|error| {
                    PlatformError::invalid("invalid JSON from /uvm/native-claim-status")
                        .with_detail(error.to_string())
                })?;
            let summary = serde_json::json!({
                "compatibility_matrix": matrix,
                "native_claim_status": native_claim,
            });
            println!(
                "{}",
                serde_json::to_string_pretty(&summary).map_err(|error| {
                    PlatformError::unavailable("failed to render UVM compatibility summary")
                        .with_detail(error.to_string())
                })?
            );
            Ok(())
        }
        _ => Err(PlatformError::invalid(
            "usage: uhostctl uvm compat check [--endpoint <url>]",
        )),
    }
}

