    use uhost_core::{base64url_encode, random_bytes, sha256_hex};

    #[derive(Debug)]
    struct RecordedRequest {
        method: String,
        path: String,
        body: serde_json::Value,
    }

    fn spawn_json_capture_server(
        response_status: &str,
        response_body: &str,
    ) -> (String, std::thread::JoinHandle<RecordedRequest>) {
        let listener = TcpListener::bind("127.0.0.1:0").unwrap_or_else(|error| panic!("{error}"));
        let address = listener
            .local_addr()
            .unwrap_or_else(|error| panic!("{error}"));
        let response_status = response_status.to_owned();
        let response_body = response_body.to_owned();
        let handle = std::thread::spawn(move || {
            let (mut stream, _) = listener.accept().unwrap_or_else(|error| panic!("{error}"));
            let mut request = Vec::new();
            let header_end = loop {
                if let Some(position) = request.windows(4).position(|window| window == b"\r\n\r\n")
                {
                    break position + 4;
                }
                let mut chunk = [0_u8; 1024];
                let read = stream
                    .read(&mut chunk)
                    .unwrap_or_else(|error| panic!("{error}"));
                if read == 0 {
                    panic!("unexpected EOF while reading request headers");
                }
                request.extend_from_slice(&chunk[..read]);
            };

            let request_head = std::str::from_utf8(&request[..header_end])
                .unwrap_or_else(|error| panic!("{error}"));
            let mut lines = request_head.split("\r\n");
            let request_line = lines
                .next()
                .unwrap_or_else(|| panic!("missing request line"));
            let mut request_parts = request_line.split_whitespace();
            let method = request_parts
                .next()
                .unwrap_or_else(|| panic!("missing request method"))
                .to_owned();
            let path = request_parts
                .next()
                .unwrap_or_else(|| panic!("missing request path"))
                .to_owned();
            let content_length = lines
                .find_map(|line| {
                    line.strip_prefix("Content-Length:")
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(|value| {
                            value
                                .parse::<usize>()
                                .unwrap_or_else(|error| panic!("{error}"))
                        })
                })
                .unwrap_or(0);
            while request.len() < header_end + content_length {
                let mut chunk = [0_u8; 1024];
                let read = stream
                    .read(&mut chunk)
                    .unwrap_or_else(|error| panic!("{error}"));
                if read == 0 {
                    panic!("unexpected EOF while reading request body");
                }
                request.extend_from_slice(&chunk[..read]);
            }
            let body = if content_length == 0 {
                serde_json::Value::Null
            } else {
                serde_json::from_slice(&request[header_end..header_end + content_length])
                    .unwrap_or_else(|error| panic!("{error}"))
            };

            let response = format!(
                "HTTP/1.1 {response_status}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{response_body}",
                response_body.len()
            );
            stream
                .write_all(response.as_bytes())
                .unwrap_or_else(|error| panic!("{error}"));

            RecordedRequest { method, path, body }
        });
        (format!("http://127.0.0.1:{}", address.port()), handle)
    }

    #[test]
    fn migration_bundle_loader_parses_and_orders_manifests() {
        let mut root = std::env::temp_dir();
        let entropy = random_bytes(6).unwrap_or_else(|error| panic!("{error}"));
        root.push(format!("uhostctl-bundle-{}", base64url_encode(&entropy)));
        let schema = root.join("schema");
        let config = root.join("config");
        std::fs::create_dir_all(&schema).unwrap_or_else(|error| panic!("{error}"));
        std::fs::create_dir_all(&config).unwrap_or_else(|error| panic!("{error}"));

        std::fs::write(
            schema.join("0002.toml"),
            r#"name = "s2"
scope = "schema"
from_version = 2
to_version = 3
checksum = "bbb"
"#,
        )
        .unwrap_or_else(|error| panic!("{error}"));
        std::fs::write(
            schema.join("0001.toml"),
            r#"name = "s1"
scope = "schema"
from_version = 1
to_version = 2
checksum = "aaa"
"#,
        )
        .unwrap_or_else(|error| panic!("{error}"));
        std::fs::write(
            config.join("0001.toml"),
            r#"name = "c1"
scope = "config"
from_version = 1
to_version = 2
checksum = "ccc"
"#,
        )
        .unwrap_or_else(|error| panic!("{error}"));

        let manifests = load_migration_manifests(&PathBuf::from(&root))
            .unwrap_or_else(|error| panic!("{error}"));
        assert_eq!(manifests.len(), 3);
        assert_eq!(manifests[0].scope, "config");
        assert_eq!(manifests[1].name, "s1");
        assert_eq!(manifests[2].name, "s2");

        let _ = std::fs::remove_dir_all(root);
    }

    #[cfg(unix)]
    #[test]
    fn migration_bundle_loader_skips_symlinked_directories() {
        use std::os::unix::fs::symlink;

        let mut root = std::env::temp_dir();
        let entropy = random_bytes(6).unwrap_or_else(|error| panic!("{error}"));
        root.push(format!(
            "uhostctl-bundle-link-{}",
            base64url_encode(&entropy)
        ));
        let schema = root.join("schema");
        let linked = root.join("linked");
        std::fs::create_dir_all(&schema).unwrap_or_else(|error| panic!("{error}"));
        std::fs::write(
            schema.join("0001.toml"),
            r#"name = "s1"
scope = "schema"
from_version = 1
to_version = 2
checksum = "aaa"
"#,
        )
        .unwrap_or_else(|error| panic!("{error}"));
        symlink(&schema, &linked).unwrap_or_else(|error| panic!("{error}"));

        let manifests = load_migration_manifests(&PathBuf::from(&root))
            .unwrap_or_else(|error| panic!("{error}"));
        assert_eq!(manifests.len(), 1);

        let _ = std::fs::remove_dir_all(root);
    }

