    #[test]
    fn release_manifest_and_provenance_validation_helpers_pass_for_valid_inputs() {
        let mut root = std::env::temp_dir();
        let entropy = random_bytes(6).unwrap_or_else(|error| panic!("{error}"));
        root.push(format!("uhostctl-release-{}", base64url_encode(&entropy)));
        std::fs::create_dir_all(&root).unwrap_or_else(|error| panic!("{error}"));

        let artifact = root.join("uhostd");
        std::fs::write(&artifact, b"artifact-bytes").unwrap_or_else(|error| panic!("{error}"));
        let digest = sha256_hex(b"artifact-bytes");
        let cargo_lock_sha256 = sha256_hex(b"Cargo.lock");

        let manifest = root.join("artifact-manifest.json");
        std::fs::write(
            &manifest,
            format!(
                r#"[{{"artifact":"uhostd","path":"{}","sha256":"{}"}}]"#,
                artifact.display(),
                digest
            ),
        )
        .unwrap_or_else(|error| panic!("{error}"));
        let manifest_entry = verify_artifact_manifest(&manifest, &artifact, &digest)
            .unwrap_or_else(|error| panic!("{error}"));
        assert_eq!(manifest_entry.artifact, "uhostd");
        assert_eq!(manifest_entry.sha256, digest);
        let manifest_sha256 =
            sha256_hex(&std::fs::read(&manifest).unwrap_or_else(|error| panic!("{error}")));

        let provenance = root.join("attestation.json");
        std::fs::write(
            &provenance,
            format!(
                r#"{{
  "builder": {{ "name": "project-uhost-ci", "version": 2 }},
  "source": {{ "repository": "Project-Uhost", "commit": "abc123", "dirty": false }},
  "build": {{
    "timestamp_utc": "2026-03-19T00:00:00Z",
    "rustc": "rustc 1.94.0",
    "cargo": "cargo 1.94.0",
    "locked": true,
    "cargo_lock_sha256": "{cargo_lock_sha256}",
    "artifact_manifest_sha256": "{manifest_sha256}",
    "artifacts": [
      {{ "artifact": "uhostd", "path": "{}", "sha256": "{}" }}
    ]
  }}
}}"#,
                artifact.display(),
                digest
            ),
        )
        .unwrap_or_else(|error| panic!("{error}"));
        let summary = verify_provenance_attestation(
            &provenance,
            Some(&artifact),
            Some(&digest),
            Some(&manifest),
        )
        .unwrap_or_else(|error| panic!("{error}"));
        assert_eq!(summary.builder, "project-uhost-ci");
        assert_eq!(summary.source_commit, "abc123");
        assert_eq!(summary.cargo_lock_sha256, cargo_lock_sha256);
        assert_eq!(summary.artifact_manifest_sha256, manifest_sha256);
        assert!(summary.locked);
        assert_eq!(
            summary
                .artifact
                .as_ref()
                .unwrap_or_else(|| panic!("missing artifact binding"))
                .artifact,
            "uhostd"
        );

        let _ = std::fs::remove_dir_all(root);
    }

